const CLINIC_ID = '51738ea8-c12e-40ce-a0e2-42869496d76b';
const raw = $json.body ?? $json;
const event = String(raw.event ?? raw.Event ?? raw.type ?? '').toLowerCase();
const data = raw.data ?? raw.Data ?? raw.payload ?? {};
const root = { ...data, ...raw };

const norm = (s) => String(s ?? '').normalize('NFD').replace(/\p{M}/gu, '').toLowerCase();

const status = norm(root.status ?? root.Status ?? root.appointmentStatus ?? root.state ?? '');
const statusName = norm(root.statusName ?? root.StatusName ?? '');
const statusState = String(root.statusState ?? root.StatusState ?? '');

const completedHints = ['completed', 'complete', 'done', 'finished', 'tamamlandi', 'bitti', 'closed'];
const isCompletedEvent = /complete|tamam|finish|done|closed/.test(event);
const isCompletedStatus =
  completedHints.some((h) => status.includes(h)) ||
  statusName.includes('tamamlandi') ||
  statusState === '+';

if (!isCompletedEvent && !isCompletedStatus) {
  return [{ json: { skip: true, reason: 'not_completed', event, status, statusName: root.statusName, statusState } }];
}

const phoneRaw =
  root.patientPhone ?? root.phone ?? root.mobile ?? root.gsm ??
  root.customerPhone ?? root.Phone ?? root.patient?.phone ?? root.customer?.phone ?? '';
const phone = String(phoneRaw).replace(/\D/g, '');

const patientName =
  root.patientName ?? root.patient ?? root.customerName ?? root.customerRepresetName ??
  root.customer?.name ?? root.patient?.name ?? 'Hasta';

const appointmentId = String(root.appointmentId ?? root.id ?? root.appointment_id ?? '');

if (!phone || phone.length < 10) {
  return [{ json: { skip: true, reason: 'missing_phone', event, appointmentId, statusName: root.statusName } }];
}

const services = root.appointmentService ?? root.services ?? [];
const treatment =
  root.treatment ?? root.service ?? root.serviceName ?? root.procedure ??
  (Array.isArray(services) && services[0]?.serviceName) ?? '';

return [{
  json: {
    skip: false,
    clinic_id: CLINIC_ID,
    patientName: String(patientName).trim(),
    patientPhone: phone,
    clinicName: root.clinicName ?? 'Medident İstanbul',
    doctorName: root.doctor ?? root.doctorName ?? root.staffName ?? root.physician ?? '',
    treatment: String(treatment).trim(),
    appointmentId: appointmentId ? `estesoft-${appointmentId}` : '',
    googleReviewUrl: root.googleReviewUrl ?? '',
    complaintFormUrl: root.complaintFormUrl ?? '',
  },
}];

const item = $json;
if (!item.appointmentId) return [{ json: item }];

const CLINIC_ID = item.clinic_id;
const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!sbKey) return [{ json: item }];

const headers = {
  apikey: sbKey,
  Authorization: `Bearer ${sbKey}`,
};

const events = await this.helpers.httpRequest({
  method: 'GET',
  url: `${sbBase}/rest/v1/automation_events?clinic_id=eq.${CLINIC_ID}&event_type=eq.estesoft_nps_triggered&payload->>appointmentId=eq.${encodeURIComponent(item.appointmentId)}&select=id,payload&limit=5`,
  headers,
  json: true,
});

if (Array.isArray(events) && events.some((r) => r.payload?.source === 'historical_seed')) {
  return [{ json: { skip: true, reason: 'historical_seed', appointmentId: item.appointmentId } }];
}

const inbox = await this.helpers.httpRequest({
  method: 'GET',
  url: `${sbBase}/rest/v1/inbox_messages?message_kind=eq.estesoft_nps&metadata->>appointmentId=eq.${encodeURIComponent(item.appointmentId)}&select=id,status&limit=5`,
  headers,
  json: true,
});

const activeInbox = Array.isArray(inbox) && inbox.some((r) => r.status === 'draft_ready' || r.status === 'replied');
if (activeInbox) {
  return [{ json: { skip: true, reason: 'dedup_inbox', appointmentId: item.appointmentId } }];
}

return [{ json: item }];

const item = $('Dedup Kontrol').first().json;
if (!item.appointmentId) return [{ json: { ok: true, skipped: true } }];

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY;
if (!sbKey) return [{ json: { ok: true, note: 'no supabase key' } }];

await this.helpers.httpRequest({
  method: 'POST',
  url: `${sbBase}/rest/v1/automation_events`,
  headers: {
    apikey: sbKey,
    Authorization: `Bearer ${sbKey}`,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal',
  },
  body: {
    clinic_id: item.clinic_id,
    workflow_name: 'Nefalix - Estesoft HBYS Adapter',
    event_type: 'estesoft_nps_triggered',
    payload: {
      appointmentId: item.appointmentId,
      patientName: item.patientName,
      source: 'adapter_draft',
    },
    status: 'success',
  },
  json: true,
});

return [{ json: { ok: true, appointmentId: item.appointmentId } }];

